css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #fff7ed; color: #1c1917; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 32px; height: 64px; background: white; box-shadow: 0 1px 8px rgba(0,0,0,0.06); position: sticky; top: 0; z-index: 100; }
.logo { font-size: 20px; font-weight: 800; color: #ea580c; }
.location { display: flex; align-items: center; gap: 6px; font-size: 14px; color: #6b7280; font-weight: 500; }
.cart-btn { display: flex; align-items: center; gap: 8px; padding: 10px 18px; border-radius: 20px; background: #ea580c; color: white; font-weight: 700; font-size: 14px; cursor: pointer; position: relative; }
.cart-badge { background: white; color: #ea580c; border-radius: 50%; width: 20px; height: 20px; display: flex; align-items: center; justify-content: center; font-size: 11px; font-weight: 900; }
.hero { background: linear-gradient(135deg, #ea580c, #dc2626); color: white; padding: 48px 32px; display: flex; justify-content: space-between; align-items: center; }
.hero-text h1 { font-size: 40px; font-weight: 900; line-height: 1.1; margin-bottom: 10px; } .hero-text p { color: rgba(255,255,255,0.8); margin-bottom: 24px; }
.hero-search { display: flex; gap: 0; max-width: 440px; }
.hero-search input { flex: 1; height: 48px; border-radius: 14px 0 0 14px; border: none; background: white; padding: 0 18px; font-size: 15px; outline: none; color: #1c1917; }
.hero-search button { height: 48px; padding: 0 24px; border-radius: 0 14px 14px 0; border: none; background: #1c1917; color: white; font-weight: 700; cursor: pointer; }
.hero-stats { display: flex; gap: 32px; } .hs-item { text-align: center; } .hs-item strong { display: block; font-size: 28px; font-weight: 900; } .hs-item span { color: rgba(255,255,255,0.7); font-size: 13px; }
.categories { background: white; padding: 12px 32px; border-bottom: 1px solid #f1f5f9; overflow-x: auto; }
.cat-scroll { display: flex; gap: 8px; white-space: nowrap; }
.cat-btn { padding: 10px 18px; border-radius: 20px; border: 1px solid #e2e8f0; background: transparent; font-size: 14px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .cat-btn.active { background: #ea580c; border-color: #ea580c; color: white; }
.restaurants { padding: 24px 32px; }
.restaurants h2 { font-size: 22px; font-weight: 800; margin-bottom: 20px; }
.rest-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px; }
.rest-card { background: white; border-radius: 16px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.06); transition: all 0.2s; cursor: pointer; } .rest-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(0,0,0,0.1); }
.rest-img { height: 160px; display: flex; align-items: center; justify-content: center; font-size: 64px; position: relative; }
.rest-badge { position: absolute; top: 12px; left: 12px; background: #22c55e; color: white; padding: 4px 10px; border-radius: 6px; font-size: 11px; font-weight: 800; }
.rest-info { padding: 14px; }
.rest-name { font-size: 16px; font-weight: 800; margin-bottom: 4px; }
.rest-meta { display: flex; gap: 12px; font-size: 12px; color: #6b7280; margin-bottom: 12px; }
.rest-categories { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 14px; }
.rest-tag { padding: 4px 10px; border-radius: 6px; background: #fff7ed; color: #ea580c; font-size: 11px; font-weight: 700; }
.rest-menu { display: flex; flex-direction: column; gap: 8px; }
.menu-item { display: flex; justify-content: space-between; align-items: center; }
.mi-name { font-size: 13px; font-weight: 600; } .mi-price { font-size: 14px; font-weight: 800; color: #ea580c; }
.mi-add { width: 28px; height: 28px; border-radius: 50%; border: none; background: #ea580c; color: white; font-size: 16px; cursor: pointer; display: flex; align-items: center; justify-content: center; }
.cart-drawer { position: fixed; right: -380px; top: 0; width: 380px; height: 100vh; background: white; z-index: 200; transition: right 0.3s; display: flex; flex-direction: column; box-shadow: -4px 0 20px rgba(0,0,0,0.1); }
.cart-drawer.open { right: 0; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 199; display: none; } .overlay.open { display: block; }
.cd-header { display: flex; justify-content: space-between; align-items: center; padding: 20px; border-bottom: 1px solid #f1f5f9; } .cd-header h3 { font-size: 18px; font-weight: 800; } .cd-header button { width: 32px; height: 32px; border-radius: 50%; border: none; background: #f1f5f9; cursor: pointer; }
.cd-items { flex: 1; overflow-y: auto; padding: 16px; }
.cd-item { display: flex; justify-content: space-between; align-items: center; padding: 12px 0; border-bottom: 1px solid #f8fafc; font-size: 14px; }
.cd-item-left { display: flex; gap: 12px; align-items: center; } .cd-item-emoji { font-size: 24px; } .cd-item-name { font-weight: 600; } .cd-item-price { color: #ea580c; font-size: 12px; }
.cd-item-remove { background: none; border: none; color: #ef4444; cursor: pointer; font-size: 18px; }
.cd-footer { padding: 16px; border-top: 1px solid #f1f5f9; }
.cd-total, .cd-delivery { display: flex; justify-content: space-between; font-size: 14px; margin-bottom: 8px; } .cd-total strong { font-size: 18px; font-weight: 900; color: #ea580c; }
.order-btn { width: 100%; height: 50px; border-radius: 14px; border: none; background: linear-gradient(135deg, #ea580c, #dc2626); color: white; font-size: 16px; font-weight: 800; cursor: pointer; margin-top: 8px; }

