const restaurants = [
  { name: 'Pizza Palace', emoji: '🍕', rating: 4.8, time: '25-35 dk', min: 50, delivery: 15, badge: 'Yeni', tags: ['pizza', 'İtalyan'], cat: 'pizza', menu: [{name:'Margarita', price:120, emoji:'🍕'},{name:'Pepperoni', price:145, emoji:'🍕'},{name:'BBQ Chicken', price:160, emoji:'🍕'}] },
  { name: 'Burger Bros', emoji: '🍔', rating: 4.6, time: '20-30 dk', min: 75, delivery: 10, badge: null, tags: ['burger', 'Fast Food'], cat: 'burger', menu: [{name:'Classic Burger', price:95, emoji:'🍔'},{name:'Double Smash', price:135, emoji:'🍔'},{name:'Chicken Burger', price:110, emoji:'🍔'}] },
  { name: 'Sushi World', emoji: '🍣', rating: 4.9, time: '30-45 dk', min: 120, delivery: 0, badge: 'Ücretsiz Teslimat', tags: ['sushi', 'Japon'], cat: 'sushi', menu: [{name:'Salmon Roll', price:180, emoji:'🍣'},{name:'Dragon Roll', price:220, emoji:'🍣'},{name:'Miso Soup', price:45, emoji:'🍜'}] },
  { name: 'Kebapçı Usta', emoji: '🥙', rating: 4.7, time: '15-25 dk', min: 60, delivery: 12, badge: null, tags: ['kebap', 'Türk'], cat: 'kebap', menu: [{name:'Adana Kebap', price:145, emoji:'🥙'},{name:'Urfa Kebap', price:140, emoji:'🥙'},{name:'Pide', price:80, emoji:'🫓'}] },
  { name: 'Tatlı Dünya', emoji: '🍰', rating: 4.5, time: '20-30 dk', min: 40, delivery: 8, badge: 'Popüler', tags: ['tatlı', 'Pasta'], cat: 'tatli', menu: [{name:'Tiramisu', price:95, emoji:'🍮'},{name:'Cheesecake', price:85, emoji:'🍰'},{name:'Brownie', price:70, emoji:'🍫'}] }
];
let cart = [], currentCat = 'all';
function renderRestaurants() {
  const visible = currentCat === 'all' ? restaurants : restaurants.filter(r => r.cat === currentCat);
  document.getElementById('rest-grid').innerHTML = visible.map((r, ri) => `
    <div class='rest-card'>
      <div class='rest-img' style='background:linear-gradient(135deg,${['#fff7ed','#fef3c7','#f0fdf4','#eff6ff','#fdf4ff'][ri%5]},${['#fed7aa','#fde68a','#bbf7d0','#bfdbfe','#e9d5ff'][ri%5]})'>${r.emoji}${r.badge ? `<div class='rest-badge'>${r.badge}</div>` : ''}</div>
      <div class='rest-info'>
        <div class='rest-name'>${r.name}</div>
        <div class='rest-meta'><span>⭐ ${r.rating}</span><span>⏱ ${r.time}</span><span>Min: ₺${r.min}</span></div>
        <div class='rest-categories'>${r.tags.map(t=>`<span class='rest-tag'>${t}</span>`).join('')}</div>
        <div class='rest-menu'>${r.menu.map(m=>`<div class='menu-item'><div class='mi-name'>${m.emoji} ${m.name}</div><div style='display:flex;align-items:center;gap:8px'><span class='mi-price'>₺${m.price}</span><button class='mi-add' onclick='addItem(${ri},"${m.name}",${m.price},"${m.emoji}")'>+</button></div></div>`).join('')}</div>
      </div>
    </div>
  `).join('');
}
function addItem(ri, name, price, emoji) {
  const ex = cart.find(c => c.name === name);
  if (ex) ex.qty++; else cart.push({name, price, emoji, qty:1});
  updateCart();
}
function removeItem(name) { cart = cart.filter(c => c.name !== name); updateCart(); }
function updateCart() {
  const total = cart.reduce((s,c)=>s+c.price*c.qty,0);
  const delivery = cart.length > 0 ? 15 : 0;
  document.getElementById('badge').textContent = cart.reduce((s,c)=>s+c.qty,0);
  document.getElementById('total').textContent = '₺' + total.toLocaleString('tr');
  document.getElementById('delivery').textContent = delivery > 0 ? '₺'+delivery : 'Ücretsiz';
  document.getElementById('cd-items').innerHTML = cart.length === 0 ? '<p style="text-align:center;color:#9ca3af;padding:40px">Sepetiniz boş 🍽️</p>' : cart.map(c=>`<div class='cd-item'><div class='cd-item-left'><span class='cd-item-emoji'>${c.emoji}</span><div><div class='cd-item-name'>${c.name} x${c.qty}</div><div class='cd-item-price'>₺${(c.price*c.qty).toLocaleString('tr')}</div></div></div><button class='cd-item-remove' onclick='removeItem("${c.name}")'>×</button></div>`).join('');
}
function toggleCart() { document.getElementById('cart').classList.toggle('open'); document.getElementById('overlay').classList.toggle('open'); }
function filterCat(cat, btn) { currentCat = cat; document.querySelectorAll('.cat-btn').forEach(b=>b.classList.remove('active')); btn.classList.add('active'); renderRestaurants(); }
function order() { if(cart.length===0){alert('Sepetiniz boş!');return;} alert('Siparişiniz alındı! 🎉\n30 dakika içinde kapınızda.'); cart=[]; updateCart(); toggleCart(); }
renderRestaurants();
